#include <bits/stdc++.h>
using namespace std;

const int N=5003;

int n,r,a[N][N],ans;

int main(){
    scanf("%d%d",&n,&r);
    for(int i=1;i<=n;i++){
        int x,y,z;
        scanf("%d%d%d",&x,&y,&z);
        a[x+1][y+1]+=z;
    }
    for(int i=1;i<=5001;i++)
        for(int j=1;j<=5001;j++)
            a[i][j]+=a[i-1][j]+a[i][j-1]-a[i-1][j-1];
    if(!r){
        printf("0");
        return 0;
    }
    r=min(r,5001);
    for(int i=r;i<=5001;i++)
        for(int j=r;j<=5001;j++)
            ans=max(ans,a[i][j]-a[i-r][j]-a[i][j-r]+a[i-r][j-r]);
    printf("%d",ans);
    return 0;
}
